func:
// ============================================================
// SINCRONIZA O MODO CONFIRMADO PELO ESP32
//
// Saída 1: valor booleano para atualizar o ui_switch
// Saída 2: comando dos LEDs ao entrar no modo automático
// ============================================================

const dados = msg.payload;

// ============================================================
// VALIDAÇÃO DA MENSAGEM
// ============================================================

if (
    !dados ||
    typeof dados !== "object" ||
    Array.isArray(dados)
) {
    node.status({
        fill: "red",
        shape: "ring",
        text: "Status inválido"
    });

    return [null, null];
}

// ============================================================
// LEITURA E VALIDAÇÃO DO MODO
// ============================================================

const modo = String(dados.modo || "")
    .trim()
    .toUpperCase();

if (
    modo !== "MANUAL" &&
    modo !== "AUTOMATICO"
) {
    node.status({
        fill: "red",
        shape: "ring",
        text: "Modo desconhecido"
    });

    return [null, null];
}

// Atualiza o modo utilizado pelos demais nós do fluxo
flow.set("modoControle", modo);

// ============================================================
// STATUS DO NÓ
// ============================================================

node.status({
    fill:
        modo === "AUTOMATICO"
            ? "green"
            : "blue",

    shape: "dot",

    text:
        modo === "AUTOMATICO"
            ? "Automático confirmado"
            : "Manual confirmado"
});

// ============================================================
// SAÍDA 1: ATUALIZAÇÃO DO SWITCH
// ============================================================

const mensagemDashboard = {
    payload: modo === "AUTOMATICO"
};

// ============================================================
// SAÍDA 2: ESTADO DOS LEDS
// ============================================================

let mensagemLeds = null;

// Ao entrar no modo automático, força o envio do último
// estado calculado a partir das leituras dos sensores.
if (modo === "AUTOMATICO") {
    let estadoSistema = String(
        flow.get("estadoAutomatico") || "NORMAL"
    )
        .trim()
        .toUpperCase();

    // Estados permitidos no modo automático
    const estadosAutomaticosValidos = [
        "NORMAL",
        "ATENCAO",
        "ALERTA_SPRINKLERS"
    ];

    // Evita utilizar valores antigos, desconhecidos
    // ou estados exclusivos do modo manual.
    if (
        !estadosAutomaticosValidos.includes(
            estadoSistema
        )
    ) {
        estadoSistema = "NORMAL";

        flow.set(
            "estadoAutomatico",
            estadoSistema
        );
    }

    mensagemLeds = {
        payload: estadoSistema,
        topic: "smokeguard/comandos/leds"
    };
}

// ============================================================
// RETORNO
// ============================================================

return [
    mensagemDashboard,
    mensagemLeds
];
